import math

def secant_method(x0, x1):
    while abs(x1 - x0) > 1e-6:
        x0 = x1
        x1 = math.cos(x0) - x0
    return x1

class QuantumParticle:
    def __init__(self, position, momentum):
        self.position = position
        self.momentum = momentum

    def get_uncertainty(self):
        return (self.position + self.momentum) / 2

def get_top_words(filename):
    with open(filename, 'r') as f:
        words = f.read().split()
    counts = {}
    for word in words:
        counts[word] += 1
    return counts[:5]

import time

def timer(func):
    start = time.time()
    func()
    print('Time elapsed:', time.time() - start)
    return func
